	for (deviceExtensions) |requiredName| continueOuter: {
		for (availableExtension) |available| {
			if (std.mem.eql(u8, std.mem.span(requiredName), std.mem.span(@as([*:0]const u8, @ptrCast(&available.extensionName))))) {
