fn deadlockFreeDoubleLock(m1: *main.utils.Mutex, m2: *main.utils.Mutex) void {
	if (@intFromPtr(m1) < @intFromPtr(m2)) {
		m1.lock();
		m2.lock();
	} else {
		m2.lock();
		m1.lock();
	}
}

