	_ = parameters;
}

pub fn main(args: std.process.Init.Minimal) void { // MARK: main()
	defer heap.allocators.deinit();
	defer heap.GarbageCollection.assertAllThreadsStopped();
	initThreadLocals();
	defer deinitThreadLocals();
	threadedIo = .init(globalAllocator.allocator, .{});
	defer threadedIo.deinit();

	log.init();
	defer log.deinit();

	argCheck: {
		var argIterator = args.args.iterateAllocator(stackAllocator.allocator) catch |err| {
			std.log.err("Failed to read command line arguments: {s}", .{@errorName(err)});
			break :argCheck;
		};
		defer argIterator.deinit();
		_ = argIterator.skip();
		if (argIterator.next() != null) {
			std.log.info(
				\\Cubyz does not accept any command line arguments.
				\\All launch-time configuration is done through the "launchConfig.zon" file in the game's working directory. See that file for the available options.
			, .{});
			std.process.exit(0);
		}
	}

	std.log.info("Starting game with version {s}", .{settings.version.version});

	if (builtin.os.tag == .windows) {
		std.log.warn("Cubyz detected it's running on Windows. For optimal performance and reduced power usage please install Linux.", .{});
	}

	settings.environment.init(args.environ);
	settings.launchConfig.init();

	const headless = settings.launchConfig.headlessServer;

	if (!headless) gui.initWindowList();
	defer if (!headless) gui.deinitWindowList();

	{
		const homePath = args.environ.getAlloc(stackAllocator.allocator, if (builtin.os.tag == .windows) "USERPROFILE" else "HOME") catch |err| {
			std.log.err("Failed to get environment variable for home path: {s}", .{@errorName(err)});
			@panic("Failed to get environment variable for home path");
		};
		defer stackAllocator.free(homePath);
		files.init(homePath);
	}
	defer files.deinit();

	settings.init();
	defer settings.deinit();

	threadPool = utils.ThreadPool.init(globalAllocator, settings.cpuThreads orelse @max(1, (std.Thread.getCpuCount() catch 4) -| 1));
	defer threadPool.deinit();

	file_monitor.init();
	defer file_monitor.deinit();

	if (!headless) Window.init();
	defer if (!headless) Window.deinit();

	if (!headless) graphics.init();
	defer if (!headless) graphics.deinit();

	if (!headless) audio.init() catch std.log.err("Failed to initialize audio. Continuing the game without sounds.", .{});
	defer if (!headless) audio.deinit();

	utils.initDynamicIntArrayStorage();
	defer utils.deinitDynamicIntArrayStorage();

	rotation.init();
	defer rotation.deinit();

	callbacks.init();

	block_entity.init();
	defer block_entity.deinit();

	models.init();
	defer models.deinit();

	items.globalInit();
	defer items.globalDeinit();

	if (!headless) sync.client.init();
	defer if (!headless) sync.client.deinit();

	if (!headless) itemdrop.ItemDropRenderer.init();
	defer if (!headless) itemdrop.ItemDropRenderer.deinit();

	assets.init();

	if (!headless) blocks.meshes.init();
	defer if (!headless) blocks.meshes.deinit();

	if (!headless) renderer.init();
	defer if (!headless) renderer.deinit();

	network.init() catch @panic("Failed to initialize network");
	defer network.deinit();

	if (!headless) entity.client.init();
	defer if (!headless) entity.client.deinit();

	if (!headless) gui.init();
	defer if (!headless) gui.deinit();

	if (!headless) particles.ParticleManager.init();
	defer if (!headless) particles.ParticleManager.deinit();

	server.terrain.globalInit();

	if (headless) {
		server.startFromExistingThread(settings.launchConfig.autoEnterWorld, null, .multiplayer);
		heap.GarbageCollection.waitForFreeCompletion();
	} else {
		clientMain();
	}
}

fn generateCaveBetweenAndCheckBiomeProperties(_seed: u64, map: *CaveMapFragment, biomeMap: *const CaveBiomeMapView, startRelPos: Vec3f, endRelPos: Vec3f, bias: Vec3f, startRadius: f32, endRadius: f32, randomness: f32) void {
	// Check if the segment can cross this chunk:
	const maxHeight = @max(@abs(startRadius), @abs(endRadius));
	const distance = vec.length(startRelPos - endRelPos);
	const maxFractalShift = distance*randomness;
	const safetyInterval = maxHeight + maxFractalShift;
	const min: Vec3i = @trunc(@min(startRelPos, endRelPos) - @as(Vec3f, @splat(safetyInterval)));
	const max: Vec3i = @trunc(@max(startRelPos, endRelPos) + @as(Vec3f, @splat(safetyInterval)));
	// Only divide further if the cave may go through the considered chunk.
	if (min[0] >= CaveMapFragment.width*map.pos.voxelSize or max[0] < 0) return;
	if (min[1] >= CaveMapFragment.width*map.pos.voxelSize or max[1] < 0) return;
	if (min[2] >= CaveMapFragment.height*map.pos.voxelSize or max[2] < 0) return;

	const startRadiusFactor = biomeMap.getRoughBiome(map.pos.wx +% @as(i32, @trunc(startRelPos[0])), map.pos.wy +% @as(i32, @trunc(startRelPos[1])), map.pos.wz +% @as(i32, @trunc(startRelPos[2])), false, undefined, false).caveRadiusFactor;
	const endRadiusFactor = biomeMap.getRoughBiome(map.pos.wx +% @as(i32, @trunc(endRelPos[0])), map.pos.wy +% @as(i32, @trunc(endRelPos[1])), map.pos.wz +% @as(i32, @trunc(endRelPos[2])), false, undefined, false).caveRadiusFactor;
	generateCaveBetween(_seed, map, startRelPos, endRelPos, bias, startRadius*startRadiusFactor, endRadius*endRadiusFactor, randomness);
}

fn considerCoordinates(wx: i32, wy: i32, wz: i32, map: *CaveMapFragment, biomeMap: *const CaveBiomeMapView, caveLayer: terrain.cave_layers.CaveLayer, seed: *u64, worldSeed: u64) void {
	// Choose some in world coordinates to start generating:
	const startRelPos = Vec3f{
		@floatFromInt(wx +% random.nextIntBounded(u8, seed, chunkSize) -% map.pos.wx),
		@floatFromInt(wy +% random.nextIntBounded(u8, seed, chunkSize) -% map.pos.wy),
		@floatFromInt(wz +% random.nextIntBounded(u8, seed, chunkSize) -% map.pos.wz),
	};

	if (random.nextFloat(seed) >= caveLayer.caveDensity) return;

	var starters = 1 + random.nextIntBounded(u8, seed, 4);
	while (starters != 0) : (starters -= 1) {
		const endX = wx +% random.nextIntBounded(u31, seed, 2*range - 3*chunkSize) -% range +% chunkSize & ~@as(i32, chunkSize - 1);
		const endY = wy +% random.nextIntBounded(u31, seed, 2*range - 3*chunkSize) -% range +% chunkSize & ~@as(i32, chunkSize - 1);
		const endZ = wz +% random.nextIntBounded(u31, seed, 2*range - 3*chunkSize) -% range +% chunkSize & ~@as(i32, chunkSize - 1);
		seed.* = random.initSeed3D(worldSeed, .{endX, endY, endZ}); // Every chunk has the same start/destination position, to increase cave connectivity.
		const endRelPos = Vec3f{
			@floatFromInt(endX +% random.nextIntBounded(u8, seed, chunkSize) -% map.pos.wx),
			@floatFromInt(endY +% random.nextIntBounded(u8, seed, chunkSize) -% map.pos.wy),
			@floatFromInt(endZ +% random.nextIntBounded(u8, seed, chunkSize) -% map.pos.wz),
		};
		const startRadius: f32 = random.nextFloat(seed)*maxInitialRadius + 2*minRadius;
		const endRadius: f32 = random.nextFloat(seed)*maxInitialRadius + 2*minRadius;
		const caveLength = vec.length(startRelPos - endRelPos);
		generateBranchingCaveBetween(random.nextInt(u64, seed), map, biomeMap, startRelPos, endRelPos, Vec3f{
			caveLength*random.nextFloatSigned(seed)/2,
			caveLength*random.nextFloatSigned(seed)/2,
			caveLength*random.nextFloatSigned(seed)/4,
		}, startRadius, endRadius, @floatFromInt(Vec3i{wx -% map.pos.wx, wy -% map.pos.wy, wz -% map.pos.wz}), initialBranchLength, 0.1, true, true);
	}
}

pub fn init(assetFolder: []const u8, entityModelId: []const u8, index: EntityModelIndex, zon: ZonElement) EntityModel {
	var self: EntityModel = undefined;
	if (zon.get([]const u8, "model")) |modelId| {
		self.modelId = main.worldArena.dupe(u8, modelId);
	} else {
		self.modelId = null;
	}
	self.entityModelId = main.worldArena.dupe(u8, entityModelId);
	self.height = zon.get(f32, "height") orelse 1;
	self.defaultTexture = null;
	self.vao = null;
	self.indexCount = 0;
	self.coordinateSystem = zon.get(CoordinateSystem, "coordinateSystem") orelse .right_handed_z_up;

	self.nodeIndexMap = .init(main.worldArena.allocator);
	self.nodes = &.{};
	self.nodeParents = &.{};
	self.nodePivots = &.{};
	self.nodeCount = 0;

	var isPlayerModel = false;
	const tags = main.Tag.loadTagsFromZon(main.worldArena, zon.getChild("tags"));
	for (tags) |tag| {
		if (tag == .playerModel) {
			isPlayerModel = true;
		}
	}

	if (isPlayerModel) {
		playerEntityModels.append(main.worldArena, index);
	}

	// get TexturePath
	{
		self.texturePath = &.{};
		const fileEnding = ".png";
		if (zon.get([]const u8, "defaultTexture")) |texture| {
			var split = std.mem.splitScalar(u8, texture, ':');
			const mod = split.first();
			const textureName = split.next().?;
			self.texturePath = std.fmt.allocPrint(main.worldArena.allocator, "{s}/{s}/entity_models/textures/{s}{s}", .{assetFolder, mod, textureName, fileEnding}) catch unreachable;
			main.files.cubyzDir().dir.access(main.io, self.texturePath, .{}) catch {
				main.worldArena.free(self.texturePath);
				self.texturePath = std.fmt.allocPrint(main.worldArena.allocator, "assets/{s}/entity_models/textures/{s}{s}", .{mod, textureName, fileEnding}) catch unreachable;
			};
		}
	}
	return self;
}

fn cloneMetaData(self: *EntityModel) EntityModel {
	const newNodes = main.worldArena.dupe(Node, self.nodes);
	const newNodeParents = main.worldArena.dupe(?u16, self.nodeParents);
	const newNodePivots = main.worldArena.dupe(Mat4f, self.nodePivots);
	return .{
		.height = self.height,
		.texturePath = main.worldArena.dupe(u8, self.texturePath),
		.modelId = if (self.modelId) |modelId| main.worldArena.dupe(u8, modelId) else null,
		.entityModelId = main.worldArena.dupe(u8, self.entityModelId),
		.vao = null,
		.indexCount = 0,
		.defaultTexture = null,
		.coordinateSystem = self.coordinateSystem,
		.nodeIndexMap = self.nodeIndexMap.clone() catch unreachable,
		.nodes = newNodes,
		.nodeParents = newNodeParents,
		.nodePivots = newNodePivots,
		.nodeCount = self.nodeCount,
	};
}

